import React, { Fragment, useEffect, useState } from 'react'
import Transparentspinner from '../../Common/Loader/Transparentspinner'
import { Col, Card, CardHeader, Media, Label, CardBody, Form, Row, Input } from 'reactstrap';
import { Area, key, key_secret, messageCredits } from '../../../Constant';
import { Breadcrumbs, H3 } from '../../../AbstractElements';
import { useForm } from 'react-hook-form';
import { yupResolver } from '@hookform/resolvers/yup';
import * as yup from "yup";
import { completecredit, getSubDetail, messageBalace, storeMessage } from '../../../CommonUrl';
import { getMasterDataToken, postMasterToken } from '../../../Utils/restUtils';
import { useSelector } from 'react-redux';
import { toast } from 'react-toastify';
import { useNavigate } from 'react-router';
import CreditHeader from './CreditHeader';
import TransactionTable from './TransactionTable';


const schema = yup.object().shape({
    amount: yup
        .number()
        .typeError("Amount must be a number")
        .required("Amount is required")
        // .min(500, "Minimum 500"),
});

function MessageCredits() {
    
    const [balanceData, setBalanceData] = useState()

    const [loading, setLoading] = useState(false)
    const [companyData, setCompanyData] = useState()
    const authState = useSelector((state) => state.auth);
    const navigate = useNavigate()



    const { register, handleSubmit, control, getValues, watch, formState: { errors } } = useForm({
        resolver: yupResolver(schema),
        mode: 'onChange',
        defaultValues: {
        }

    })

    const amountValue = watch('amount', 0);


    const handleGetCompanyDetails = async () => {
        const response = await getMasterDataToken(getSubDetail);

        setCompanyData(response?.data)
    }
    useEffect(() => {
        handleGetCompanyDetails()
        handleGetCreditDetails()
    }, [])







    const creditPackages = [
        { credits: 500, price: 500, whatsapp: 500, sms: 1000 },
        { credits: 750, price: 750, whatsapp: 500, sms: 1000 },
        { credits: 1000, price: 1000, whatsapp: 500, sms: 1000 },
        { credits: 1500, price: 1500, whatsapp: 500, sms: 1000 },
        { credits: 2000, price: 2000, whatsapp: 500, sms: 1000 },
        { credits: 2500, price: 2500, whatsapp: 500, sms: 1000 },
        { credits: 3000, price: 3000, whatsapp: 500, sms: 1000 },
        { credits: 3500, price: 3500, whatsapp: 500, sms: 1000 }
    ];

    const handleGetCreditDetails = async () => {
        let data = await getMasterDataToken(messageBalace + `?user_id=${authState?.userId}`);
        if (data?.status === true) {
            setBalanceData(data?.data)
        } else if (data?.status >= 400 && data?.status <= 405) {
            navigate(`${process.env.PUBLIC_URL}/pages/error/error-page1`);
        } else if (data?.status >= 500 && data?.status <= 505) {
            navigate(`${process.env.PUBLIC_URL}/pages/error/error-page4`);
        }
        else {
            navigate(`${process.env.PUBLIC_URL}/pages/error/error-page3`);
        }

    }


    const handlePayment = async (amount) => {
        setLoading(true);
        const result = await postMasterToken(storeMessage, { industry_id: authState?.industryId, user_id: authState?.userId, amount: amount });
        if (result.status === 200) {
            if (result.data.status === true) {
                const oderData = result.data.data
                // const { id: orderId, email: email, name: name, mobile: mobile, amount: amount, currency: currency } = result.data.data;
                if (oderData?.amount === "") {
                    alert("please enter amount");
                } else {
                    ``
                    var options = {
                        key: key,
                        key_secret: key_secret,
                        amount: oderData?.amount.toString(),
                        currency: 'INR',
                        name: "BillerQ",
                        description: "for testing purpose",
                        order_id: oderData?.reference_id,
                        handler: async function (response) {
                            const data = {
                                // orderCreationId: orderId,
                                razorpayPaymentId: response.razorpay_payment_id,
                                razorpay_order_id: response.razorpay_order_id,
                                razorpay_signature: response.razorpay_signature,
                                amount: amount,
                                user_id: authState?.userId,
                                company_id: companyData?.company_id,
                                industry_id: authState?.industryId
                            };
                            setLoading(true);
                            const payment = await postMasterToken(completecredit, data);
                            if (payment.status === 200) {
                                if (payment.data.status === true) {
                                    toast.success(payment.data.message);
                                    navigate('/settings/message-credit');
                                } else {
                                    toast.error(payment.data.message);
                                    setLoading(false);
                                }
                            }
                        },
                        prefill: {
                            name: authState?.userName,
                            email: authState?.email,
                            contact: oderData?.mobile
                        },
                        notes: {
                            address: "Razorpay Corporate office"
                        },
                        theme: {
                            color: "#3399cc"
                        }
                    };
                    var pay = new window.Razorpay(options);
                    pay.open();
                }
            } else {
                toast.error(result.data.message);
                setLoading(false);
            }
        }
        setLoading(false);
    }


    return (
        <div className='message-credit'>
            <Breadcrumbs mainTitle={messageCredits} parent="Settings" title={messageCredits} />
            {
                loading && <Transparentspinner />
            }

            <Card className="container-fluid" style={{ minHeight: '100vh', padding: '30px' }}>

                {/* Header Section */}
                <div className="row mb-4">
                    <CardHeader className="col-12 border rounded-lg" >

                        <CreditHeader balanceData={balanceData} />
                    </CardHeader>
                </div>

                {/* Buy Credits Section */}
                <div className="row mb-5">
                    <H3 >Buy Credits</H3>
                    <div className="col-md-9">
                        <div className="row g-3">
                            {creditPackages.map((pkg, index) => (
                                <div key={index} className="col-xxl-3 col-md-4 col-sm-6">
                                    <div className="credit-card">
                                        <div className="credit-amount">
                                            {pkg.credits} <span className="credit-label">Credits</span>
                                        </div>
                                        <div className="credit-detail">{(pkg.credits / balanceData?.whatsapp_rate).toFixed(0)} Whatsapp  messages</div>
                                        <div className='credit-detail my-2'>OR</div>
                                        <div className="credit-detail mb-3">{(pkg.credits / balanceData?.sms_rate).toFixed(0)} SMS</div>
                                        <button onClick={() => handlePayment(pkg?.price)} className="btn buy-btn w-100">
                                            Buy for ₹ {pkg.price}
                                        </button>
                                    </div>
                                </div>
                            ))}
                        </div>
                    </div>
                    <div className="col-md-3">
                        <H3 >Custom Amount</H3>

                        {/* <h5 className="fw-semibold mb-3">Buy Credits</h5> */}
                        <div className="row g-3">

                            <div className="col-12">
                                <form onSubmit={handleSubmit((data) => handlePayment(data.amount))}>
                                    <div className="custom-credit-card">
                                        <div className="credit-amunt">
                                            <span className="creit-label">Enter Amount</span>
                                        </div>
                                        <div className='d-flex mt-3'>
                                            <input
                                                {...register('amount')}
                                                className='message-credit-input'
                                                type="number"
                                                onWheel={(e) => e.currentTarget.blur()}
                                            />
                                        </div>
                                        {
                                            errors?.amount?.message &&
                                            <p className=' mt-2 position-absolute'>*{errors?.amount?.message}</p>
                                        }
                                        {
                                            amountValue == 0 ?
                                                <div style={{ marginTop: '30px' }} className='mb-4'>
                                                    <span>Enter an amount to find the approx count of messages</span>

                                                </div>
                                                :

                                                <div style={{ marginTop: '30px' }} className='mb-4'>
                                                    <span className="creditdetail"> {(amountValue / balanceData?.whatsapp_rate).toFixed(0)} Whatsapp  messages</span>
                                                    <br />
                                                    <div className='credit-d my-2'>OR</div>

                                                    <span className="creditdetail mb-3">{(amountValue / balanceData?.sms_rate).toFixed(0)} SMS</span>
                                                </div>

                                        }
                                        <button type='submit' className="btn buy-btn-custom w-100">
                                            Buy

                                        </button>
                                    </div>

                                </form>
                            </div>
                        </div>
                    </div>
                </div>

                {/* Recent Transactions Section */}
                
                <TransactionTable />
            </Card>
        </div>
    );
}
export default MessageCredits
