import React, { useEffect, useState } from 'react'
import { Media, Label, Input } from 'reactstrap';
import { getClientUrlDataToken, getMasterDataToken, postClientUrlWithToken, postDataWithToken, postMasterToken } from '../../../Utils/restUtils';
import { useSelector } from 'react-redux';
import { getmessageChannel, getmessageChannelRole, messageBalace, messageChannelUpdate, messageChannelUpdateRole } from '../../../CommonUrl';
import { useNavigate } from 'react-router';
import Transparentspinner from '../../Common/Loader/Transparentspinner';
import { toast } from 'react-toastify';


function CreditHeader({ balanceData }) {
    const [chkeckvalue, setChkeckvalue] = useState({
        whatsApp: '',
        sms: ''
    })
    const [loading, setLoading] = useState(false)
    const navigate = useNavigate()
    const authState = useSelector((state) => state.auth);




    const getNotificationCannel = async () => {
        setLoading(true)
        let data = await getClientUrlDataToken(authState.apiUrl, authState.userRole === 1 ? getmessageChannel : getmessageChannelRole)
        if (data?.status === true) {
            setChkeckvalue({ ...chkeckvalue, whatsApp: data?.data?.whatsapp_enabled || 'no', sms: data?.data?.sms_enabled || 'no' })
            setLoading(false)
        }
        else if (data?.status >= 400 && data.status <= 405) {
            navigate(`${process.env.PUBLIC_URL}/pages/error/error-page1`);
        } else if (data?.status >= 500 && data.status <= 505) {
            navigate(`${process.env.PUBLIC_URL}/pages/error/error-page4`);
        }
        else {
            navigate(`${process.env.PUBLIC_URL}/pages/error/error-page3`);
        }

        setLoading(false)
    }


    const handleSwitchToggle = async (value, channel) => {
        setLoading(true)
        const postRequest = channel == 'sms' ? {
            sms_enabled: value,
            whatsapp_enabled: chkeckvalue.whatsApp,
        } : {
            whatsapp_enabled: value,
            sms_enabled: chkeckvalue.sms,
        }


        const responce = await postClientUrlWithToken(authState.apiUrl, authState.userRole === 1 ? messageChannelUpdate : messageChannelUpdateRole, postRequest)
        if (responce?.status === 200) {

            getNotificationCannel()
            toast.success(responce?.data?.message)
            setLoading(false)

        }
        else if (responce?.status >= 400 && responce.status <= 405) {
            navigate(`${process.env.PUBLIC_URL}/pages/error/error-page1`);
        } else if (responce?.status >= 500 && responce.status <= 505) {
            navigate(`${process.env.PUBLIC_URL}/pages/error/error-page4`);
        }
        else {
            navigate(`${process.env.PUBLIC_URL}/pages/error/error-page3`);
        }

        setLoading(false)
    }

    useEffect(() => {
        getNotificationCannel()

    }, [])
    return (
        <>
            {
                loading && <Transparentspinner />
            }

            <div className="d-flex  justify-content-between align-items-center flex-wrap gap-3">
                <div className="">

                    <span className="credits-badge py-3" style={{ fontWeight: '400' }}>
                        <span className='me-2' style={{ fontSize: '18px', fontWeight: '500' }}>
                            {balanceData?.balance || 0}
                        </span>Credits Available
                    </span>
                    <br />
                    <p className="price-info mt-4">
                        WhatsApp = ₹ {balanceData?.whatsapp_rate}/message &nbsp;&nbsp; SMS = ₹ {balanceData?.sms_rate}/message
                    </p>
                </div>
                <div>
                    <div className="d-flex flex-sm-row flex-column align-items-center gap-4">
                        <div className="d-flex align-items-center gap-3 ">
                            <div>
                                <div className="toggle-label">WhatsApp</div>
                                <div className="toggle-subtext">Approx {(balanceData?.balance / balanceData?.whatsapp_rate).toFixed(0)} messages</div>
                            </div>
                            <Media body className={`flex-grow-1 text-end icon-state`}>
                                <Label className="switch ">
                                    <Input type="checkbox"

                                        disabled={balanceData?.whatsapp_enabled !== 'yes'}
                                        checked={chkeckvalue.whatsApp === "yes"} // controlled by state
                                        onChange={(event) => {
                                            const newValue = event.target.checked ? "yes" : "no";
                                            setChkeckvalue({ ...chkeckvalue, whatsApp: newValue }); // update your state
                                            handleSwitchToggle(newValue, 'whatsapp'); // send value to your function
                                        }}
                                    />
                                    <span className={`switch-state  ${balanceData?.whatsapp_enabled !== 'yes' && "bg-light"}`} ></span>
                                </Label>
                            </Media>
                        </div>
                        <div className='d-sm-block d-none' style={{ border: 'solid 1px #cbcbcb', height: '30px' }}></div>
                        <div className="d-flex align-items-center gap-3">
                            <div>
                                <div className="toggle-label">SMS</div>
                                <div className="toggle-subtext">Approx {(balanceData?.balance / balanceData?.sms_rate).toFixed(0)} messages</div>
                            </div>
                            <Media body className={`flex-grow-1 text-end icon-state `} >
                                <Label className="switch">
                                    <input type="checkbox"
                                        disabled={balanceData?.sms_enabled !== 'yes'}
                                        checked={chkeckvalue.sms === "yes"} // controlled by state
                                        onChange={(event) => {
                                            const newValue = event.target.checked ? "yes" : "no";
                                            setChkeckvalue({ ...chkeckvalue, sms: newValue }); // update your state
                                            handleSwitchToggle(newValue, 'sms'); // send value to your function
                                        }}
                                    />
                                    <span className={`switch-state  ${balanceData?.sms_enabled !== 'yes' && "bg-light"}`} ></span>
                                </Label>
                            </Media>
                        </div>
                    </div>
                    {
                        (chkeckvalue?.sms==='no' && chkeckvalue?.whatsApp==='no') &&
                    <div className='mt-2'>
                        <p style={{fontSize:'12px' }}>* Kindly enable SMS or WhatsApp service to send messages *</p>
                    </div>
                    }
                </div>
            </div>
        </>
    )
}

export default CreditHeader