import React, { useEffect, useState } from 'react'
import { H3, H4 } from '../../../AbstractElements';
import { getMasterDataToken } from '../../../Utils/restUtils';
import { getShareApi, messageLogs, messageTransaction } from '../../../CommonUrl';
import { useSelector } from 'react-redux';
import { useNavigate } from 'react-router';
import { Nav, NavItem, NavLink, TabContent, TabPane } from 'reactstrap';
import { Invoice, Payment, Transactions, whatsappLog } from '../../../Constant';
import DataTable from 'react-data-table-component';

function TransactionTable() {
    const [transactionTable, setTranctionTable] = useState([])
    const [messageLogData, setMessageLog] = useState([])
    const [totalRows, setTotalRows] = useState(0);
    const [perPage, setPerPage] = useState(10);
    const [currentPage, setCurrentPage] = useState(1);



    const authState = useSelector((state) => state.auth);
    const navigate = useNavigate()


    const redirectToInvoice = async (data) => {
        let response = await getMasterDataToken(getShareApi + `?order_id=${data.order_id}`);
        if (response.status === true) {
            const toReciept = `${process.env.PUBLIC_URL}/invoice?order_id=${response.data}`;
            navigate(toReciept);
        }
    };

    const logsTable = () => [
        {
            name: <H4>Sl.No</H4>,
            selector: row => row.Si,
            width: '70px',
            center: true
        },

        {
            name: <H4>Txn ID</H4>,
            id: 'name',
            selector: row => row.transaction_id,
            sortable: true,
            minWidth: '140px',
            wrap: true
        },
        {
            name: <H4>Invoice ID</H4>,
            id: 'invoice',
            selector: row =>
                <div style={{ textDecoration: 'underline', color: '#534686', cursor: 'pointer' }} onClick={() => redirectToInvoice(row)}>
                    {row.invoice}
                </div>,
            sortable: true,
            minWidth: '200px',
            wrap: true
        },
        {
            name: <H4>Credit Pack</H4>,
            id: 'creDate',
            selector: row => row.amount + ' Credit',
            sortable: true,
            minWidth: '140px',
            wrap: true
        },
        {
            name: <H4>Amount</H4>,
            id: 'amount',
            selector: row => "₹ " + row.amount,
            sortable: true,
            minWidth: '140px',
            wrap: true
        },
        {
            name: <H4>Date</H4>,
            id: 'amount',
            selector: row => row.created,
            sortable: true,
            minWidth: '140px',
            wrap: true
        },

    ];



    const handlePageChange = page => {
        handleGetCreditDetails(page);
        setCurrentPage(page);
    };

    const handlePerRowsChange = async (newPerPage, page) => {
        handleGetCreditDetails(page, newPerPage);
        setPerPage(newPerPage);
    };

    const handleGetCreditDetails = async (page = currentPage, size = perPage) => {
        let data = await getMasterDataToken(messageTransaction + `?user_id=${authState?.userId}&page=${page}&page_length=${size}`);

        if (data.status === true) {
            if (data.data && Array.isArray(data.data.data)) {
                const SerialNo = (page - 1) * size + 1;
                setTranctionTable(data.data.data.map((e, index) => {
                    return {
                        Si: SerialNo + index,
                        transaction_id: e?.transaction_id,
                        created: e.created_date,
                        messageType: e.message_type,
                        amount: e.amount,
                        invoice: e.invoice_number,
                        order_id:e?.order_id
                    }
                }))
                setTotalRows(data.data.total);
            }

        } else if (data.status >= 400 && data.status <= 405) {
            navigate(`${process.env.PUBLIC_URL}/pages/error/error-page1`);
        } else if (data.status >= 500 && data.status <= 505) {
            navigate(`${process.env.PUBLIC_URL}/pages/error/error-page4`);
        }
        else {
            navigate(`${process.env.PUBLIC_URL}/pages/error/error-page3`);
        }

    }




    useEffect(() => {
        handleGetCreditDetails(1)

    }, [])

    return (
        <div className="row">

            <div className="col-12">
                <H3 >Recent Transactions</H3>
                <div className="table-responsive">
                    <DataTable
                        columns={logsTable()}
                        data={transactionTable}
                        pagination
                        paginationServer
                        defaultSortAsc
                        paginationRowsPerPageOptions={[10, 25, 50, 100]}
                        paginationTotalRows={totalRows}
                        paginationDefaultPage={currentPage}
                        onChangeRowsPerPage={handlePerRowsChange}
                        onChangePage={handlePageChange}
                    />


                </div>
            </div>
        </div>
    )
}

export default TransactionTable